    @rpc(Unicode, Unicode, Decimal, _returns=TransferResult)
    def transferFunds(ctx, from_account, to_account, amount):
        """
        Transfer funds between accounts
        SOAPAction: transferFunds
        """
        global transactions_counter
        
        logger.info(f"transferFunds called: {from_account} -> {to_account}, amount: {amount}")
        
        result = TransferResult()
        
        # Validation checks
        if from_account not in accounts_db:
            result.success = "false"
            result.message = f"Source account {from_account} not found"
            result.transaction_id = ""
            result.new_balance = Decimal(0)
            logger.error(result.message)
            return result
        
        if to_account not in accounts_db:
            result.success = "false"
            result.message = f"Destination account {to_account} not found"
            result.transaction_id = ""
            result.new_balance = Decimal(0)
            logger.error(result.message)
            return result
        
        if amount <= 0:
            result.success = "false"
            result.message = "Transfer amount must be positive"
            result.transaction_id = ""
            result.new_balance = Decimal(str(accounts_db[from_account]["balance"]))
            logger.error(result.message)
            return result
        
        from_balance = Decimal(str(accounts_db[from_account]["balance"]))
        
        if from_balance < amount:
            result.success = "false"
            result.message = "Insufficient funds"
            result.transaction_id = ""
            result.new_balance = from_balance
            logger.error(f"Insufficient funds in {from_account}")
            return result
        
        # Perform transfer
        accounts_db[from_account]["balance"] = float(from_balance - amount)
        to_balance = Decimal(str(accounts_db[to_account]["balance"]))
        accounts_db[to_account]["balance"] = float(to_balance + amount)
        
        transactions_counter += 1
        transaction_id = f"TXN{transactions_counter}"
        
        result.success = "true"
        result.transaction_id = transaction_id
        result.message = f"Successfully transferred {amount} from {from_account} to {to_account}"
        result.new_balance = Decimal(str(accounts_db[from_account]["balance"]))
        
        logger.info(f"Transfer successful: {transaction_id}")
